    console.log('Triggering workflow...');
    const triggerResult = await knockNode.workflows.trigger(workflowKey, {
      tenant: tenantId,
      recipients: [
        {
          id: recipientId,
          email: recipientEmail,
          name: `User ${runId}`
        }
      ]
    });

